import React from "react";
import "../styles/about.css"; // Import the about.css file

const About = () => {
  return (
    <section id="about" className="section about-section">
      <div className="about-container">
        <div className="about-text">
          <h1>About Us</h1>
          <p>
            Welcome to [Your Law Firm's Name], where we believe in providing exceptional legal 
            services tailored to your unique needs. With years of experience in [specific legal 
            areas], our team of professionals is committed to delivering justice, clarity, and peace 
            of mind.
          </p>
        </div>

        <div className="about-images">
          <img src="/images/about.jpg" alt="Law Firm" />
        </div>
      </div>
    </section>
  );
};

export default About;
